#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=2e2+5;
int p;
ll f[MAXN]={0},tmp[MAXN]={0},ans=0;
string s;
int main(void)
{
    p=read();
    cin>>s;
	for(int i=0;i<s.size();++i)
    {
	    int c=(s[i]-'0')%p;
		for(int j=0;j<p;++j)
        {
           f[(j*10+c)%p]+=tmp[j];
        }
		++f[c];
        ans+=f[0];
		for(int j=0;j<p;++j)
        {
            tmp[j]=f[j],f[j]=0;
        }
	}
    write(ans);
	return false;
}
